import { jest } from '@jest/globals';
import AgentOrchestrator from '../src/agent/AgentOrchestrator.js';

// Mock dependencies
const mockMistralClient = {
  registerTools: jest.fn(),
  sendWithTools: jest.fn(),
};

const mockToolRegistry = {
  getToolDefinitions: jest.fn(),
  executeTool: jest.fn(),
};

const mockApprovalManager = {
  requestApproval: jest.fn(),
};

const mockContextManager = {
  addMessage: jest.fn(),
  getMessages: jest.fn(),
};

describe('AgentOrchestrator', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  describe('Constructor', () => {
    it('should throw error without MistralClient', () => {
      expect(() => new AgentOrchestrator(null, mockToolRegistry)).toThrow('MistralClient is required');
    });

    it('should throw error without ToolRegistry', () => {
      expect(() => new AgentOrchestrator(mockMistralClient, null)).toThrow('ToolRegistry is required');
    });

    it('should initialize with default options', () => {
      const orchestrator = new AgentOrchestrator(mockMistralClient, mockToolRegistry);
      
      expect(orchestrator.options.maxToolCalls).toBe(10);
      expect(orchestrator.options.maxIterations).toBe(20);
      expect(orchestrator.options.streamResponses).toBe(true);
      expect(orchestrator.options.displayToolCalls).toBe(true);
    });

    it('should accept custom options', () => {
      const options = {
        maxToolCalls: 5,
        maxIterations: 15,
        streamResponses: false,
        displayToolCalls: false,
      };
      
      const orchestrator = new AgentOrchestrator(mockMistralClient, mockToolRegistry, null, options);
      
      expect(orchestrator.options.maxToolCalls).toBe(5);
      expect(orchestrator.options.maxIterations).toBe(15);
      expect(orchestrator.options.streamResponses).toBe(false);
      expect(orchestrator.options.displayToolCalls).toBe(false);
    });

    it('should initialize with approval manager', () => {
      const orchestrator = new AgentOrchestrator(mockMistralClient, mockToolRegistry, mockApprovalManager);
      
      expect(orchestrator.approvalManager).toBe(mockApprovalManager);
    });
  });

  describe('processMessage', () => {
    let orchestrator;

    beforeEach(() => {
      orchestrator = new AgentOrchestrator(mockMistralClient, mockToolRegistry);
      mockContextManager.getMessages.mockReturnValue([]);
      mockToolRegistry.getToolDefinitions.mockReturnValue([]);
    });

    it('should throw error for invalid user message', async () => {
      await expect(orchestrator.processMessage('', mockContextManager)).rejects.toThrow('User message must be a non-empty string');
      await expect(orchestrator.processMessage(null, mockContextManager)).rejects.toThrow('User message must be a non-empty string');
      await expect(orchestrator.processMessage(123, mockContextManager)).rejects.toThrow('User message must be a non-empty string');
    });

    it('should throw error without ContextManager', async () => {
      await expect(orchestrator.processMessage('Hello', null)).rejects.toThrow('ContextManager is required');
    });

    it('should throw error if already processing', async () => {
      orchestrator.isProcessing = true;
      
      await expect(orchestrator.processMessage('Hello', mockContextManager)).rejects.toThrow('Agent is already processing a message');
    });

    it('should add user message to context', async () => {
      mockMistralClient.sendWithTools.mockResolvedValue({
        content: 'Hello back!',
        role: 'assistant',
        finishReason: 'stop',
      });

      await orchestrator.processMessage('Hello', mockContextManager);

      expect(mockContextManager.addMessage).toHaveBeenCalledWith('user', 'Hello');
    });

    it('should handle simple response without tool calls', async () => {
      const aiResponse = {
        content: 'Hello back!',
        role: 'assistant',
        finishReason: 'stop',
        usage: { totalTokens: 10 },
      };

      mockMistralClient.sendWithTools.mockResolvedValue(aiResponse);

      const result = await orchestrator.processMessage('Hello', mockContextManager);

      expect(result.content).toBe('Hello back!');
      expect(result.role).toBe('assistant');
      expect(result.finishReason).toBe('stop');
      expect(result.iterations).toBe(1);
      expect(result.toolCallsUsed).toBe(0);
      expect(mockContextManager.addMessage).toHaveBeenCalledWith('assistant', 'Hello back!');
    });

    it('should reset processing state after completion', async () => {
      mockMistralClient.sendWithTools.mockResolvedValue({
        content: 'Response',
        role: 'assistant',
        finishReason: 'stop',
      });

      expect(orchestrator.isProcessing).toBe(false);
      
      await orchestrator.processMessage('Hello', mockContextManager);
      
      expect(orchestrator.isProcessing).toBe(false);
    });

    it('should reset processing state after error', async () => {
      // Mock to always fail to trigger max iterations
      mockMistralClient.sendWithTools.mockRejectedValue(new Error('API Error'));

      expect(orchestrator.isProcessing).toBe(false);
      
      // The orchestrator handles errors gracefully and returns a result instead of throwing
      const result = await orchestrator.processMessage('Hello', mockContextManager);
      
      expect(result.error).toBe(true);
      expect(result.finishReason).toBe('max_iterations');
      expect(orchestrator.isProcessing).toBe(false);
    });
  });

  describe('executeAgentLoop', () => {
    let orchestrator;

    beforeEach(() => {
      orchestrator = new AgentOrchestrator(mockMistralClient, mockToolRegistry);
      mockContextManager.getMessages.mockReturnValue([
        { role: 'user', content: 'Hello' }
      ]);
      mockToolRegistry.getToolDefinitions.mockReturnValue([
        {
          type: 'function',
          function: {
            name: 'read_file',
            description: 'Read a file',
            parameters: {
              type: 'object',
              properties: {
                path: { type: 'string' }
              }
            }
          }
        }
      ]);
    });

    it('should handle tool calls and continue loop', async () => {
      // First response with tool call
      const toolCallResponse = {
        toolCalls: [
          {
            id: 'call_123',
            function: {
              name: 'read_file',
              arguments: '{"path": "test.txt"}'
            }
          }
        ],
        role: 'assistant',
        finishReason: 'tool_calls',
      };

      // Second response with final answer
      const finalResponse = {
        content: 'File content processed successfully',
        role: 'assistant',
        finishReason: 'stop',
      };

      mockMistralClient.sendWithTools
        .mockResolvedValueOnce(toolCallResponse)
        .mockResolvedValueOnce(finalResponse);

      mockToolRegistry.executeTool.mockResolvedValue({
        success: true,
        result: 'File content here'
      });

      const result = await orchestrator.executeAgentLoop(mockContextManager);

      expect(result.content).toBe('File content processed successfully');
      expect(result.iterations).toBe(2);
      expect(result.toolCallsUsed).toBe(1);
      expect(mockToolRegistry.executeTool).toHaveBeenCalledWith('read_file', { path: 'test.txt' });
    });

    it('should handle multiple tool calls in sequence', async () => {
      const toolCallResponse1 = {
        toolCalls: [
          {
            id: 'call_1',
            function: {
              name: 'read_file',
              arguments: '{"path": "file1.txt"}'
            }
          }
        ],
        role: 'assistant',
        finishReason: 'tool_calls',
      };

      const toolCallResponse2 = {
        toolCalls: [
          {
            id: 'call_2',
            function: {
              name: 'read_file',
              arguments: '{"path": "file2.txt"}'
            }
          }
        ],
        role: 'assistant',
        finishReason: 'tool_calls',
      };

      const finalResponse = {
        content: 'Both files processed',
        role: 'assistant',
        finishReason: 'stop',
      };

      mockMistralClient.sendWithTools
        .mockResolvedValueOnce(toolCallResponse1)
        .mockResolvedValueOnce(toolCallResponse2)
        .mockResolvedValueOnce(finalResponse);

      mockToolRegistry.executeTool
        .mockResolvedValueOnce({ success: true, result: 'Content 1' })
        .mockResolvedValueOnce({ success: true, result: 'Content 2' });

      const result = await orchestrator.executeAgentLoop(mockContextManager);

      expect(result.content).toBe('Both files processed');
      expect(result.iterations).toBe(3);
      expect(result.toolCallsUsed).toBe(2);
      expect(mockToolRegistry.executeTool).toHaveBeenCalledTimes(2);
    });

    it('should handle multiple tool calls in single response', async () => {
      const multiToolResponse = {
        toolCalls: [
          {
            id: 'call_1',
            function: {
              name: 'read_file',
              arguments: '{"path": "file1.txt"}'
            }
          },
          {
            id: 'call_2',
            function: {
              name: 'read_file',
              arguments: '{"path": "file2.txt"}'
            }
          }
        ],
        role: 'assistant',
        finishReason: 'tool_calls',
      };

      const finalResponse = {
        content: 'Both files read successfully',
        role: 'assistant',
        finishReason: 'stop',
      };

      mockMistralClient.sendWithTools
        .mockResolvedValueOnce(multiToolResponse)
        .mockResolvedValueOnce(finalResponse);

      mockToolRegistry.executeTool
        .mockResolvedValueOnce({ success: true, result: 'Content 1' })
        .mockResolvedValueOnce({ success: true, result: 'Content 2' });

      const result = await orchestrator.executeAgentLoop(mockContextManager);

      expect(result.content).toBe('Both files read successfully');
      expect(result.iterations).toBe(2);
      expect(result.toolCallsUsed).toBe(2);
      expect(mockToolRegistry.executeTool).toHaveBeenCalledTimes(2);
    });

    it('should stop at max iterations', async () => {
      const orchestrator = new AgentOrchestrator(mockMistralClient, mockToolRegistry, null, {
        maxIterations: 2
      });

      // Always return tool calls to create infinite loop
      mockMistralClient.sendWithTools.mockResolvedValue({
        toolCalls: [
          {
            id: 'call_123',
            function: {
              name: 'read_file',
              arguments: '{"path": "test.txt"}'
            }
          }
        ],
        role: 'assistant',
        finishReason: 'tool_calls',
      });

      mockToolRegistry.executeTool.mockResolvedValue({
        success: true,
        result: 'File content'
      });

      const result = await orchestrator.executeAgentLoop(mockContextManager);

      expect(result.error).toBe(true);
      expect(result.finishReason).toBe('max_iterations');
      expect(result.iterations).toBe(2);
      expect(result.content).toContain('exceeded maximum iterations');
    });

    it('should handle tool execution errors gracefully', async () => {
      const toolCallResponse = {
        toolCalls: [
          {
            id: 'call_123',
            function: {
              name: 'read_file',
              arguments: '{"path": "nonexistent.txt"}'
            }
          }
        ],
        role: 'assistant',
        finishReason: 'tool_calls',
      };

      const recoveryResponse = {
        content: 'File not found, but I can help with other tasks',
        role: 'assistant',
        finishReason: 'stop',
      };

      mockMistralClient.sendWithTools
        .mockResolvedValueOnce(toolCallResponse)
        .mockResolvedValueOnce(recoveryResponse);

      mockToolRegistry.executeTool.mockResolvedValue({
        success: false,
        error: 'File not found'
      });

      const result = await orchestrator.executeAgentLoop(mockContextManager);

      expect(result.content).toBe('File not found, but I can help with other tasks');
      expect(result.iterations).toBe(2);
      expect(result.toolCallsUsed).toBe(1);
    });

    it('should call callbacks when provided', async () => {
      const onToolCall = jest.fn();
      const onToolResult = jest.fn();
      const onResponse = jest.fn();

      const toolCallResponse = {
        toolCalls: [
          {
            id: 'call_123',
            function: {
              name: 'read_file',
              arguments: '{"path": "test.txt"}'
            }
          }
        ],
        role: 'assistant',
        finishReason: 'tool_calls',
      };

      const finalResponse = {
        content: 'Task completed',
        role: 'assistant',
        finishReason: 'stop',
      };

      mockMistralClient.sendWithTools
        .mockResolvedValueOnce(toolCallResponse)
        .mockResolvedValueOnce(finalResponse);

      mockToolRegistry.executeTool.mockResolvedValue({
        success: true,
        result: 'File content'
      });

      await orchestrator.executeAgentLoop(mockContextManager, {
        onToolCall,
        onToolResult,
        onResponse
      });

      expect(onToolCall).toHaveBeenCalledWith('read_file', { path: 'test.txt' }, expect.any(String));
      expect(onToolResult).toHaveBeenCalledWith(expect.objectContaining({
        success: true,
        result: 'File content'
      }));
      expect(onResponse).toHaveBeenCalledWith('Task completed', finalResponse);
    });
  });

  describe('handleToolCall', () => {
    let orchestrator;

    beforeEach(() => {
      orchestrator = new AgentOrchestrator(mockMistralClient, mockToolRegistry);
    });

    it('should handle valid tool call', async () => {
      const toolCall = {
        id: 'call_123',
        function: {
          name: 'read_file',
          arguments: '{"path": "test.txt"}'
        }
      };

      mockToolRegistry.executeTool.mockResolvedValue({
        success: true,
        result: 'File content'
      });

      const result = await orchestrator.handleToolCall(toolCall);

      expect(result.success).toBe(true);
      expect(result.result).toBe('File content');
      expect(result.toolName).toBe('read_file');
      expect(result.arguments).toEqual({ path: 'test.txt' });
      expect(mockToolRegistry.executeTool).toHaveBeenCalledWith('read_file', { path: 'test.txt' });
    });

    it('should handle tool call with object arguments', async () => {
      const toolCall = {
        id: 'call_123',
        function: {
          name: 'read_file',
          arguments: { path: 'test.txt' }
        }
      };

      mockToolRegistry.executeTool.mockResolvedValue({
        success: true,
        result: 'File content'
      });

      const result = await orchestrator.handleToolCall(toolCall);

      expect(result.success).toBe(true);
      expect(mockToolRegistry.executeTool).toHaveBeenCalledWith('read_file', { path: 'test.txt' });
    });

    it('should handle invalid JSON arguments', async () => {
      const toolCall = {
        id: 'call_123',
        function: {
          name: 'read_file',
          arguments: '{"invalid": json}'
        }
      };

      const result = await orchestrator.handleToolCall(toolCall);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Failed to parse tool arguments');
      expect(mockToolRegistry.executeTool).not.toHaveBeenCalled();
    });

    it('should handle tool execution failure', async () => {
      const toolCall = {
        id: 'call_123',
        function: {
          name: 'read_file',
          arguments: '{"path": "nonexistent.txt"}'
        }
      };

      mockToolRegistry.executeTool.mockResolvedValue({
        success: false,
        error: 'File not found'
      });

      const result = await orchestrator.handleToolCall(toolCall);

      expect(result.success).toBe(false);
      expect(result.error).toBe('File not found');
    });

    it('should handle approval manager approval', async () => {
      const orchestrator = new AgentOrchestrator(mockMistralClient, mockToolRegistry, mockApprovalManager);
      
      const toolCall = {
        id: 'call_123',
        function: {
          name: 'write_file',
          arguments: '{"path": "test.txt", "content": "Hello"}'
        }
      };

      mockApprovalManager.requestApproval.mockResolvedValue(true);
      mockToolRegistry.executeTool.mockResolvedValue({
        success: true,
        result: 'File written'
      });

      const result = await orchestrator.handleToolCall(toolCall);

      expect(mockApprovalManager.requestApproval).toHaveBeenCalledWith('write_file', {
        path: 'test.txt',
        content: 'Hello'
      });
      expect(result.success).toBe(true);
    });

    it('should handle approval manager denial', async () => {
      const orchestrator = new AgentOrchestrator(mockMistralClient, mockToolRegistry, mockApprovalManager);
      
      const toolCall = {
        id: 'call_123',
        function: {
          name: 'write_file',
          arguments: '{"path": "test.txt", "content": "Hello"}'
        }
      };

      mockApprovalManager.requestApproval.mockResolvedValue(false);

      const result = await orchestrator.handleToolCall(toolCall);

      expect(result.success).toBe(false);
      expect(result.error).toBe('Tool execution denied by user');
      expect(mockToolRegistry.executeTool).not.toHaveBeenCalled();
    });

    it('should call callbacks when provided', async () => {
      const onToolCall = jest.fn();
      const onToolResult = jest.fn();

      const toolCall = {
        id: 'call_123',
        function: {
          name: 'read_file',
          arguments: '{"path": "test.txt"}'
        }
      };

      mockToolRegistry.executeTool.mockResolvedValue({
        success: true,
        result: 'File content'
      });

      const result = await orchestrator.handleToolCall(toolCall, onToolCall, onToolResult);

      expect(onToolCall).toHaveBeenCalledWith('read_file', { path: 'test.txt' }, expect.any(String));
      expect(onToolResult).toHaveBeenCalledWith(result);
    });
  });

  describe('shouldContinue', () => {
    let orchestrator;

    beforeEach(() => {
      orchestrator = new AgentOrchestrator(mockMistralClient, mockToolRegistry);
    });

    it('should continue if there are tool calls', () => {
      const response = {
        toolCalls: [{ id: 'call_123' }],
        content: null
      };

      expect(orchestrator.shouldContinue(response)).toBe(true);
    });

    it('should continue if no content provided', () => {
      const response = {
        toolCalls: null,
        content: null
      };

      expect(orchestrator.shouldContinue(response)).toBe(true);
    });

    it('should stop if final content provided', () => {
      const response = {
        toolCalls: null,
        content: 'Final response'
      };

      expect(orchestrator.shouldContinue(response)).toBe(false);
    });
  });

  describe('getState', () => {
    let orchestrator;

    beforeEach(() => {
      orchestrator = new AgentOrchestrator(mockMistralClient, mockToolRegistry);
    });

    it('should return current state', () => {
      orchestrator.isProcessing = true;
      orchestrator.currentIteration = 5;
      orchestrator.toolCallHistory = [{ toolName: 'read_file' }];

      const state = orchestrator.getState();

      expect(state.isProcessing).toBe(true);
      expect(state.currentIteration).toBe(5);
      expect(state.toolCallHistory).toHaveLength(1);
      expect(state.maxIterations).toBe(20);
      expect(state.maxToolCalls).toBe(10);
    });
  });

  describe('reset', () => {
    let orchestrator;

    beforeEach(() => {
      orchestrator = new AgentOrchestrator(mockMistralClient, mockToolRegistry);
    });

    it('should reset agent state', () => {
      orchestrator.isProcessing = true;
      orchestrator.currentIteration = 5;
      orchestrator.toolCallHistory = [{ toolName: 'read_file' }];

      orchestrator.reset();

      expect(orchestrator.isProcessing).toBe(false);
      expect(orchestrator.currentIteration).toBe(0);
      expect(orchestrator.toolCallHistory).toHaveLength(0);
    });
  });

  describe('getToolCallStats', () => {
    let orchestrator;

    beforeEach(() => {
      orchestrator = new AgentOrchestrator(mockMistralClient, mockToolRegistry);
    });

    it('should return empty stats for no tool calls', () => {
      const stats = orchestrator.getToolCallStats();

      expect(stats.totalCalls).toBe(0);
      expect(stats.successfulCalls).toBe(0);
      expect(stats.failedCalls).toBe(0);
      expect(stats.toolUsage).toEqual({});
    });

    it('should calculate stats correctly', () => {
      orchestrator.toolCallHistory = [
        { toolName: 'read_file', success: true },
        { toolName: 'read_file', success: false },
        { toolName: 'write_file', success: true },
      ];

      const stats = orchestrator.getToolCallStats();

      expect(stats.totalCalls).toBe(3);
      expect(stats.successfulCalls).toBe(2);
      expect(stats.failedCalls).toBe(1);
      expect(stats.toolUsage.read_file).toEqual({
        count: 2,
        successes: 1,
        failures: 1
      });
      expect(stats.toolUsage.write_file).toEqual({
        count: 1,
        successes: 1,
        failures: 0
      });
    });
  });
});